#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b){return (*(int*)a)-(*(int*)b);} 
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d",&N,&M);
        int total=N*M;
        int *arr=malloc(total*sizeof(int));
        for(int i=0;i<total;i++) scanf("%d",&arr[i]);
        qsort(arr,total,sizeof(int),cmp);
        for(int i=0;i<N;i++){
            int start=i*M;
            for(int j=M-1;j>=0;j--){
                printf("%d",arr[start+j]);
                if(j) printf(" ");
            }
            printf("\n");
        }
        free(arr);
    }
    return 0;
}

