const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let output = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const M = data[idx++];
  const total = N * M;
  const arr = data.slice(idx, idx + total);
  idx += total;
  arr.sort((a, b) => a - b);
  for (let i = 0; i < N; i++) {
    const start = i * M;
    const row = arr.slice(start, start + M).reverse();
    output.push(row.join(' '));
  }
}
console.log(output.join('\n'));

